import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils; // You can use Apache Commons Text library for HTML escaping

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input by escaping special characters
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println(sanitizedInput); // Sanitized user input
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
